"""llm_providers module settings store (initialized on extension load)."""from __future__ import annotationsfrom dataclasses import dataclassfrom pathlib import Pathfrom typing import ClassVarfrom .interfaces.response_logger import ResponseLoggerProtocol@dataclass(frozen=True)class LLMProvidersConfig:    """Provider enable flags and credentials from the `[API]` app.ini section."""    PROVIDER_KEY_ATTR: ClassVar[dict[str, str]] = {        "anthropic": "anthropic_api_key",        "google": "google_api_key",        "openai": "openai_api_key",        "xai": "xai_api_key",    }    anthropic_provider_enabled: bool = False    anthropic_api_key: str = ""    google_provider_enabled: bool = False    google_api_key: str = ""    openai_provider_enabled: bool = False    openai_api_key: str = ""    xai_provider_enabled: bool = False    xai_api_key: str = ""    gateway_timeout: int = 30    def is_provider_available(self, provider_code: str) -> bool:        """True if provider is enabled in config and has API key (or key not required)."""        if provider_code == "mock":            return True        attr = f"{provider_code}_provider_enabled"        if not getattr(self, attr, False):            return False        key_attr = self.PROVIDER_KEY_ATTR.get(provider_code)        if not key_attr:            return True        value = getattr(self, key_attr, None) or ""        return bool(str(value).strip())    def is_provider_enabled(self, provider_code: str) -> bool:        """Alias for is_provider_available (backward compatibility)."""        return self.is_provider_available(provider_code)@dataclass(frozen=True)class ModuleParams:    """Module params used to build the provider registry."""    # API keys and provider enable flags    providers: LLMProvidersConfig    # Optional raw API response logger    response_logger: ResponseLoggerProtocol | None = None    # Chat response cache dir; None disables cache    cache_path: Path | None = Noneclass ModuleStore:    _params: ModuleParams | None = None    @classmethod    def setup(cls, params: ModuleParams) -> None:        cls._params = params    @classmethod    def get(cls) -> ModuleParams:        if cls._params is None:            raise RuntimeError("llm_providers store is not initialized")        return cls._params    @classmethod    def reset(cls) -> None:        cls._params = Nonedef llm_providers_set_cache_path(cache_path: Path | None) -> None:    """Update ModuleStore params with the given cache_path."""    params = ModuleStore.get()    new_params = ModuleParams(        providers=params.providers,        response_logger=params.response_logger,        cache_path=cache_path,    )    ModuleStore.setup(new_params)def llm_providers_set_providers_config(config: LLMProvidersConfig) -> None:    """Update provider configuration in the module store (no restart)."""    params = ModuleStore.get()    new_params = ModuleParams(        providers=config,        response_logger=params.response_logger,        cache_path=params.cache_path,    )    ModuleStore.setup(new_params)